- (void)loadDualAppsWithCallback:(VAppsDataLoadCallback)callback {
    if (self.dualApps) {
        if (callback) callback(self.dualApps, TRUE);
    } else {
        [WBNetworkManager.defaultManager getDualVAppsWithCount:NSIntegerMax callback:^(NSArray<WBVAppBaseHttpModel *> * _Nullable vApps, NSError * _Nullable error) {
            if (error) {
                if (callback) callback(nil, FALSE);
            } else {
                self.dualApps = [self parseVAppHttpModelList:vApps];
                for(WBVAppModel* vapp in self.dualApps) {
                    vapp.dual = TRUE;
                    vapp.isDownload = NO;
                }

                NSMutableSet *downloadedIDs = [NSMutableSet set];
                for (WBVAppModel *app in self.myApps) {
                    [downloadedIDs addObject:@(app.vid)];
