#pragma mark - launchScreen

- (void)setupLaunchScreen {
    self.view.backgroundColor = [UIColor whiteColor];
    [self.view addSubview:self.launchImageView];
}

- (UIImageView *)launchImageView {
    if (!_launchImageView) {
        _launchImageView = [[UIImageView alloc] initWithImage:[UIImage imageNamed:ABBridge_GetAppLaunchImageName()]];
        _launchImageView.frame = self.view.bounds;
    }
    return _launchImageView;
}

- (void)setupNetworkPermissionMonitor {
    self.cellularData = [[CTCellularData alloc] init];
    __weak typeof(self) weakSelf = self;
    self.cellularData.cellularDataRestrictionDidUpdateNotifier = ^(CTCellularDataRestrictedState state) {
        dispatch_async(dispatch_get_main_queue(), ^{
            if (state == kCTCellularDataRestricted) {
                if (!weakSelf.networkPermissionAlertShown) {
                    [weakSelf presentNetworkPermissionAlert];
                }
            } else {
                [weakSelf dismissNetworkPermissionAlertIfNeeded];
            }
        });
    };
    CTCellularDataRestrictedState current = self.cellularData.restrictedState;
    if (current == kCTCellularDataRestricted && !self.networkPermissionAlertShown) {
        [self presentNetworkPermissionAlert];
    } else {
        [self dismissNetworkPermissionAlertIfNeeded];
    }
}

- (void)presentNetworkPermissionAlert {
    self.networkPermissionAlertShown = YES;
    NSString *appDisplayName = ABBridge_GetLocalizedAppName();
    NSString *title = @"使用需要访问无线数据";
    NSString *messageTemplate = @"\n当无线数据关闭时，无法正常使用\n开启流程：\n【设置】-【App】-【APP_NAME】-【无线数据】";
    NSString *message = [messageTemplate stringByReplacingOccurrencesOfString:@"APP_NAME" withString:appDisplayName];
    UIAlertController *alert = [UIAlertController alertControllerWithTitle:title message:message preferredStyle:UIAlertControllerStyleAlert];

    UIAlertAction *exitAction = [UIAlertAction actionWithTitle:@"退出" style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
        exit(0);
    }];
    [exitAction setValue:WBColorHex(0x666666) forKey:@"titleTextColor"];

    UIAlertAction *settingsAction = [UIAlertAction actionWithTitle:@"去设置" style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
        NSURL *url = [NSURL URLWithString:UIApplicationOpenSettingsURLString];
        if ([[UIApplication sharedApplication] canOpenURL:url]) {
            [[UIApplication sharedApplication] openURL:url options:@{} completionHandler:nil];
        }
    }];
    [settingsAction setValue:WBColorHex(0x4063E7) forKey:@"titleTextColor"];

    [alert addAction:exitAction];
    [alert addAction:settingsAction];
    self.networkPermissionAlertController = alert;
    [self presentViewController:alert animated:YES completion:nil];
}

- (void)dismissNetworkPermissionAlertIfNeeded {
    if (self.networkPermissionAlertController) {
        [self.networkPermissionAlertController dismissViewControllerAnimated:YES completion:nil];
        self.networkPermissionAlertController = nil;
        self.networkPermissionAlertShown = NO;
    }
}

- (void)_syncAlertFlagWithVisibility {
    if (self.networkPermissionAlertController && self.networkPermissionAlertController.presentingViewController == nil) {
        self.networkPermissionAlertController = nil;
        self.networkPermissionAlertShown = NO;
    }
}

- (void)_onAppDidBecomeActive {
    [self _syncAlertFlagWithVisibility];
    if (!self.cellularData) {
        [self setupNetworkPermissionMonitor];
        return;
    }
    CTCellularDataRestrictedState current = self.cellularData.restrictedState;
    if (current == kCTCellularDataRestricted) {
        if (!self.networkPermissionAlertShown) {
            [self presentNetworkPermissionAlert];
        }
    } else {
        [self dismissNetworkPermissionAlertIfNeeded];
    }
}


