#pragma mark singleton & init

+ (instancetype)sharedManager {
    static id instance;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[self alloc] init];
    });
    return instance;
}


- (instancetype)init {
    self = [super init];

    // roots initialization
    _docRoot = [[NSSearchPathForDirectoriesInDomains(NSLibraryDirectory, NSUserDomainMask, YES) firstObject] stringByAppendingPathComponent:[WBUtility getCodeNameSaltedCrc32Hash:kDocRoot]];
    _tmpRoot = [NSTemporaryDirectory() stringByAppendingPathComponent:[WBUtility getCodeNameSaltedCrc32Hash:kTmpRoot]];
    _cacheRoot = [[NSSearchPathForDirectoriesInDomains(NSCachesDirectory, NSUserDomainMask, YES) firstObject] stringByAppendingPathComponent:[WBUtility getCodeNameSaltedCrc32Hash:kCacheRoot]];
    _unzipResCompletionHandler = [NSMutableDictionary dictionary];
    _resCleanupStates = [NSMutableDictionary dictionary];
    if ([NSFileManager.defaultManager fileExistsAtPath:_docRoot] == FALSE) {
        [NSFileManager.defaultManager createDirectoryAtPath:_docRoot withIntermediateDirectories:YES attributes:nil error:nil];
    }
    if ([NSFileManager.defaultManager fileExistsAtPath:_tmpRoot] == FALSE) {
        [NSFileManager.defaultManager createDirectoryAtPath:_tmpRoot withIntermediateDirectories:YES attributes:nil error:nil];
    }
    if ([NSFileManager.defaultManager fileExistsAtPath:_cacheRoot] == FALSE) {
        [NSFileManager.defaultManager createDirectoryAtPath:_cacheRoot withIntermediateDirectories:YES attributes:nil error:nil];
    }

    _installedVAppListFilePath = [_docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kInstalledVAppList]];
    _searchHistoryFilePath = [_docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kSearchHistoryList]];
    _crashReportDirPath = [_docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kCrashReportDir]];
    _deleteUncleanedVAppListFilePath = [_docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kDeleteUncleanedVappList]];
    _appConfigFilePath = [_docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kAppGlobalConfig]];
    _routeLogFilePath = [_docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kRouteLogFile]];
    BOOL isCrashReportDirExist = false;
    [[NSFileManager defaultManager] fileExistsAtPath:_crashReportDirPath isDirectory:&isCrashReportDirExist];
    if (!isCrashReportDirExist) {
        [NSFileManager.defaultManager createDirectoryAtPath:_crashReportDirPath withIntermediateDirectories:YES attributes:nil error:nil];
    }
    _crashReportFilePath = [_crashReportDirPath stringByAppendingPathComponent:@"crash.log"];
    [self initializeChatDatabase];
    return self;
}

- (void)initializeChatDatabase {
    _databaseQueue = dispatch_queue_create("com.webox.sqlite.queue", DISPATCH_QUEUE_SERIAL);

    dispatch_sync(_databaseQueue, ^{
        _chatDBPath = [self.docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kAIChatsSqlite]];

        if (sqlite3_open(self.chatDBPath.UTF8String, &_chatDatabase) != SQLITE_OK) {
            NSLog(@"Failed to open chat database");
            return;
        }

        // 创建会话表
        const char *createSessionTableSQL = "CREATE TABLE IF NOT EXISTS sessions ("
                                            "id TEXT PRIMARY KEY,"
                                            "agent_name TEXT NOT NULL,"
                                            "created_at DATETIME DEFAULT CURRENT_TIMESTAMP,"
                                            "latest_message TEXT);";

        // 创建消息表
        const char *createMessageTableSQL = "CREATE TABLE IF NOT EXISTS messages ("
                                            "id TEXT PRIMARY KEY,"
                                            "session_id TEXT NOT NULL,"
                                            "content TEXT NOT NULL,"
                                            "is_sender BOOLEAN NOT NULL,"
                                            "timestamp DATETIME DEFAULT CURRENT_TIMESTAMP,"
                                            "done BOOLEAN DEFAULT 0,"
                                            "context TEXT,"
                                            "FOREIGN KEY(session_id) REFERENCES sessions(id) ON DELETE CASCADE);";

        char *errorMsg;
        if (sqlite3_exec(_chatDatabase, createSessionTableSQL, NULL, NULL, &errorMsg) != SQLITE_OK) {
            NSLog(@"Failed to create sessions table: %s", errorMsg);
            sqlite3_free(errorMsg);
        }

        if (sqlite3_exec(_chatDatabase, createMessageTableSQL, NULL, NULL, &errorMsg) != SQLITE_OK) {
            NSLog(@"Failed to create messages table: %s", errorMsg);
            sqlite3_free(errorMsg);
        }

        // 启用外键支持
        sqlite3_exec(_chatDatabase, "PRAGMA foreign_keys = ON;", NULL, NULL, NULL);
    });
}

- (void)dealloc {
    if (_chatDatabase) {
        sqlite3_close(_chatDatabase);
        _chatDatabase = nil;
    }
}


#pragma mark - file system version & migration
//
// migrate old app data to new app data, run it in a non-main thread if the migration might take a long time in the future
//
- (void)fileSystemVersionCheck {
    NSInteger currentVersion = WBSettingManager.sharedManager.FileSystemVersion;
    if (currentVersion == fileSystemVersionEmpty) {
        // its a fresh installation OR its an old filesystem with no filesystem version number
        //
        // we identify old filesystem by the existense of file "wb_vapp_status.plist"
        NSString *oldInstalledVAppListFilePath = [NSSearchPathForDirectoriesInDomains(NSDocumentDirectory, NSUserDomainMask, YES).firstObject stringByAppendingPathComponent:@"wb_vapp_status.plist"];
        if ([NSFileManager.defaultManager fileExistsAtPath:oldInstalledVAppListFilePath]) {
            currentVersion = fileSystemVersionClassic;
        }
    }
    if (currentVersion != kNewestFileSystemVersion) {
        [self migrateFrom:currentVersion to:kNewestFileSystemVersion];
        WBSettingManager.sharedManager.FileSystemVersion = kNewestFileSystemVersion;
    }
}


- (void)migrateFrom:(NSInteger)from to:(NSInteger)to{
    while(from != to) {
        switch(from) {
            case fileSystemVersionEmpty:
                return;
            case fileSystemVersionClassic:
                from = [self migrateFromClassicToStorageManager];
            case fileSystemVersionWithStorageManager:
                return;
            default:
                NSAssert(false, @"invalid file system version");
                return;
        }
    }
}
